	 *
	 * @var string
	 */
	$home_url = get_option( 'home' );

	$parsed_home = wp_parse_url( $home_url );

	if ( ! $parsed_home ) {
		return false;
	}

	$same_host = isset( $parsed_home['host'] ) && strtolower( $parsed_home['host'] ) === strtolower( $parsed_url['host'] );
