		! isset( $parsed_url['port'] ) ||
		( \is_array( $allowed_ports ) && \in_array( $parsed_url['port'], $allowed_ports, true ) )
	) {
		return $validated_url;
	}

	if ( $same_host && isset( $parsed_home['port'] ) && $parsed_home['port'] === $parsed_url['port'] ) {
		return $validated_url;
	}

	return false;
