	{
		$tags = $this->fixTags($tags);
		$this->append(array('mixin', $tags, $argv, $suffix), $s);
		return true;
	} else {
		$this->seek($s);
	}

	// spare ;
	if ($this->literal(';')) return true;

	return false; // got nothing, throw error
}

